<template>
  <div>
    <my-header
      :user="user"
      :orders="orders"
      @clearUser="clearUser"
    />
    <my-nav />
    <div 
      class="content"
      v-show="list"
    >
      <div class="sort_kind">
        <span>全部</span>&gt;
        <span>{{ sortedText }}</span>
      </div>
      <div class="sort">
        <span 
          class="commen"
          :class="{'active':index === i}"
          v-for="(item,index) of sort"
          :key="index"
          @click="i =index"
        >{{ item }}</span>
      </div>
      <div class="item_list">
        <div 
          class="item"
          v-for="(item,k) of list.currentPageData"
          :key="k"
        >
          <div 
            class="item_container"
            @click.stop="onDetail"
            :data-id="item.id"
            :data-pid="item.pid"
          >
            <div class="item_img_address">
              <img :src="item.foot_img">
              <div class="item_address">
                <i class="fa fa-user-o" />{{ item.address }}
              </div>
            </div>
            <div class="title">
              {{ item.foot_name }}
            </div>
            <div class="notice">
              {{ item.foot_notice }}
            </div>
            <div 
              class="reduce"
              v-if="item.reduce_price"
            >
              立减{{ item.reduce_price|fixTwo }}元
            </div>
            <div class="price">
              ￥<span class="newPrice">{{ item.new_price }}</span>
              <span class="oldPrice"> 价值￥<del>{{ item.old_price }}</del></span>
            </div>
            <div class="buy_infomation">
              <span class="source">{{ item.foot_source }}</span>分
              <span class="has_sold">已售{{ item.foot_sold }}份</span>
            </div>
          </div>
        </div>
      </div>
      <div 
        class="sort_page"
      >
        <span 
          class="prev"
          @click="prev"
        >上一页</span>
        <span 
          class="page_point"
          v-for="(item,index) of list.pages_show"
          :class="{'active': item == list.currentPage }"
          :key="index"
          @click="getPage(item)"
        >{{ item }}</span>
        <span 
          class="next"
          @click="next"
        >下一页</span>
        <span class="current_page">当前第{{ list.currentPage }}页</span>
        <input 
          type="type"
          class="input_txt"
          v-model.number="inputNum"
        >
        <span 
          class="confirm"
          @click="getPage(inputNum)"
        >确定</span>
        <span class="page_total">总共{{ list.pages }}页</span>
      </div>
    </div>
    <my-footer />
  </div>
</template>
<script>
import listApi from "../api/list/api.js";
import myHeader from "../commen/components/header.vue";
import myFooter from "../commen/components/footer.vue";
import myNav from "./nav.vue";
export default {
    data (){
        return {
            // 输入框中要获取的页码数据
            inputNum:1,
            // 分类下的全部商品
            list:[],
            sort:["默认","销量↓","价格↓","最新发布↑"],
            // 商品排序索引
            i:0,
            // 商品所属分类,
            sortedText:"",
            // 用户信息
            user:{},
            // 预购买数量
            orders:0
        };
    },
    filters:{
        fixTwo (value){
            return value.toFixed(2);

        }

    },
    created (){
        this.getPage(1);
        this. getSortedText();
        this.getUser();
        this.getUserOrders();

    },
    components:{
        myNav,
        myHeader,
        myFooter
    },
    methods: {
        // 获取用户信息
        getUser (){
            this.axios.get(`${listApi.user}`).then(response => {
                if(response.code === 200){
                    this.user = response.data;
                }
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        // 获取用户订单数
        getUserOrders (){
            this.axios.get(listApi.orders).then(response => {
                if(response.code === 200){

                    this.orders = response.data.order_num;
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        // 用户推出
        clearUser (){
            this.user = { };
            this.orders = 0;

        },
        /**
         * 获取分类下的商品
         * @param pageCode 获取哪一页的商品数据
         */
        getPage (pageCode){
            // 分类
            const currentElementId = this.$route.params.currentElementId;
            this.axios.get(`${listApi.itemList}/${currentElementId}/${pageCode}`).then(response => {
                if(response.code === 200){
                    this.list = response.data;

                }
                return;
            }).catch(error => {
                console.log(error);
            });


        },
        // 获取商品所属份额类
        getSortedText(){
            // 分类id
            const currentElementId = this.$route.params.currentElementId;
            this.axios.get(`${listApi.sorted}/${currentElementId}`).then(response => {
                if(response.code === 200){
                    this.sortedText = response.data.sorted_text;
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        // 前往商品详情页
        onDetail (event){
            let currentElementId = event.target.dataset.id,
                currentElementPid = event.target.dataset.pid;
            this.$router.push({
                path:`/productionDetail/${currentElementPid}/${currentElementId}`
            });

        },
        // 下一页
        next (){
            let pageCode = this.list.currentPage;
            ++pageCode;
            if(pageCode > this.list.pages){
                pageCode = this.list.pages;
            }
            this.getPage(pageCode);

        },
        // 上一页
        prev (){
            let pageCode = this.list.currentPage;
            --pageCode;
            if(pageCode < 1){
                pageCode = 1;
            }
            this.getPage(pageCode);

        },
    }
    
};
</script>
<style lang="scss" scoped>
.content{
    width:1200px;
    margin:20px auto 0 auto;
   .sort{
        $height:45px;
        height:$height;
        background-color:rgb(229,229,229);
         box-shadow: 0 0 3px 0 rgb(125,125,125);
        .commen{
            line-height:$height;
            height:$height;
            display:inline-block;
            padding:0 15px;
            cursor: pointer;
            font-size:14px;
            font-weight:300;
            &:hover{
                color:#e4007f;
            }
        }
        .active{
            background-color:whitesmoke;
            border-left:1px solid rgb(125,125,125);
            border-right:1px solid rgb(125,125,125);
        }
    }
    .item_list{
        margin-top:20px;
        height:630px;
        overflow:hidden;
         .item{
            width:230px;
            height:280px;
            float:left;
            padding:10px 5px 23px 5px ;
            overflow:hidden;
            border-bottom:1px solid rgb(201,201,201);
            .item_container{
                width:100%;
                height:100%;
                padding-top:5px;
                position:relative;
                
                &::after{
                    content: "";
                    width: 237px ;
                    height:100%;
                    display:inline-block;
                    position:absolute;
                    top:0;
                    left:-5px;
                    cursor: pointer;
                    border:1px solid transparent;


                    
                }

                &:hover{
                    &::after{
                        border:1px solid #e4007f;

                    }
                    .item_address{
                        opacity:0.8;
                        background-color:rgb(49,49,49);
                    }
                }
                .title{
                    font-size:15px;
                    font-weight:bold;
                    margin-top:10px;
                    letter-spacing:2px;
                }
                .notice{
                    font-size:13px;
                    color:rgb(98,98,98);
                }
                .reduce{
                    background-color:#e4007f;
                    color:whitesmoke;
                    border-radius:2px;
                    padding:0 5px;
                    display:inline;
                    position:relative;
                    top:20px;
                }
                .price{
                    position: absolute;
                    top:230px;
                    color:#e4007f;
                    font-size:16px;
                    .newPrice{
                    font-size:22px;
                    font-weight:500;
                    }
                    .oldPrice{
                        font-size:13px;
                        margin-left:5px;
                        color:rgb(160,160,160);
                    }

                }
                .buy_infomation{
                    position: absolute;;
                    top:265px;
                    font-size:12px;
                     color:rgb(160,160,160);
                     .source{
                         color:rgb(0,117,169);
                     }
                     .has_sold{
                         margin-left:117px;
                     }
                }
            }
            .item_img_address{
                position:relative;
                width:100%;
                height:135px;
                
                img{
                    width:100%;
                    height:100%;

                }
                .item_address{
                    padding-left:5px;
                    width:225px;
                    height:30px;
                    position:absolute;
                    bottom:0px;
                    color:whitesmoke;
                    transition: all 0.3s ease-in;
                    opacity:0;
                    font-size:13px;
                    line-height:30px;
                    font-weight: 600;
                    .fa{
                        padding-right:5px;
                    }
                }

            }
        }
    }
    .sort_page{
        padding-top:30px;
        padding-bottom:10px;
        border-bottom:1px solid rgb(191,191,191);
        height:30px;
        width:100%;
        overflow:hidden;
        .page_point,.prev,.next{
            padding:4px 9px;
            text-align:center;
            line-height:20px;
            border:1px solid rgb(229,229,229);
            float:left;
            margin-left:20px;
            cursor: pointer;
            border-radius: 5px;
            user-select: none;
            &:hover{
                background-color:rgb(210,210,210);
            }
            &:first-child{
                margin:0;
            }
        }
        .active{
            background-color:rgb(210,210,210);
        }
        .current_page,.input_txt,.confirm,.page_total{
            float:left;
            margin-left:20px;
            line-height:30px;
        }
        .current_page{
            margin-left:400px;
        }
        .input_txt{
            height:18px;
            width:70px;
            margin-top:5px;
            padding-left:5px;
        }
        .confirm{
            padding:0 7px;
            border:1px solid rgb(229,229,229);
            border-radius:5px;
            cursor: pointer;
            &:hover{
                background-color:rgb(210,210,210);
            }
        }

    }
    .sort_kind{
        $height:30px;
        height:$height;
        line-height:$height;
        display:inline-block;
        padding:0 10px;
        border:1px solid rgb(110,110,110);
        border-radius:4px;
        margin-bottom:20px;
        letter-spacing:3px;
    }


}

</style>

